// Récupère playbooks & escalations
const playbooks = items[0].json.response.playbooks || [];
const escalations = items[0].json.response["escalations rules"] || [];
const history = items[0].json.response["conversation historique"] || [];

// BUILD PLAYBOOKS TEXT
let playbooksOutput = "PLAYBOOKS:\n\n";
for (const pb of playbooks) {
  playbooksOutput += `ID: ${pb._id}\n`;
  playbooksOutput += `Title: ${pb.title}\n`;
  if (pb.audience) playbooksOutput += `Audience: ${pb.audience}\n`;
  if (pb.rules) playbooksOutput += `Rules: ${pb.rules}\n`;
  playbooksOutput += `Enabled: ${pb.enabled}\n\n---\n\n`;
}

// BUILD ESCALATION RULES TEXT
let escalationOutput = "ESCALATION RULES:\n\n";
for (const esc of escalations) {
  escalationOutput += `ID: ${esc._id}\n`;
  escalationOutput += `Title: ${esc.title}\n`;
  if (esc.audience) escalationOutput += `Audience: ${esc.audience}\n`;
  if (esc.trigger) escalationOutput += `Trigger: ${esc.trigger}\n`;
  if (esc.rules) escalationOutput += `Rules: ${esc.rules}\n`;
  escalationOutput += `Enabled: ${esc.enabled}\n\n---\n\n`;
}

// BUILD CONVERSATION HISTORY (ordre chronologique)
let historyOutput = "";
const sortedHistory = history.sort((a, b) => a["Created Date"] - b["Created Date"]);

for (const msg of sortedHistory) {
  historyOutput += `Human: ${msg["1 user input "]?.trim() || ""}\n`;
  historyOutput += `AI: ${msg["2 agent output"]?.trim() || ""}\n`;
}

// RETURN
return [
  {
    json: {
      playbooks_text: playbooksOutput,
      escalation_rules_text: escalationOutput,
      conversation_history: historyOutput
    }
  }
];

const params = $('Get user parameters').first().json.response;
const escalationRules = params["escalations rules"] || [];
const routingOutput = $('Routing agent').first().json.output;
const activeId = routingOutput.id || null;

let activeItem = null;

for (let i = 0; i < escalationRules.length; i++) {
  if (escalationRules[i]._id === activeId) {
    activeItem = escalationRules[i];
    break;
  }
}

return [
  {
    json: {
      activeType: "escalation",
      activeId: activeId,
      activeItem: activeItem || {},
      activeText: activeItem ? activeItem.title : "Not found"
    }
  }
];

// Récupérer les paramètres du node "Get user parameters"
const params = $('Get user parameters').first().json.response || {};

// Extraire listes
const playbooks = params.playbooks || [];
const escalations = params.escalation_rules || [];

// Récupérer l'output du routing agent
const routed = $input.first().json.output || {};
const activeType = routed.type;
const activeId = routed.id;

// Variables
let activeItem = null;

// LOGIQUE DE RÉCUPÉRATION
if (activeType === "scenario") {
  activeItem = playbooks.find(pb => pb._id === activeId);
} else if (activeType === "escalation") {
  activeItem = escalations.find(er => er._id === activeId);
}

// Si introuvable → fallback
if (!activeItem) {
  return [
    {
      json: {
        activeType,
        activeId,
        activeItem: null,
        activeText: `❌ Aucun ${activeType} trouvé pour l'ID : ${activeId}`
      }
    }
  ];
}

// FORMATAGE
let cleanText = "";

if (activeType === "scenario") {
  cleanText = `
### Scenario
**ID:** ${activeId}
**Title:** ${activeItem.title}
**Audience:** ${activeItem.audience || "N/A"}
**Content:** ${activeItem.content || "N/A"}
**Rules:** ${activeItem.rules || "N/A"}
  `.trim();
}

if (activeType === "escalation") {
  cleanText = `
### Escalation
**ID:** ${activeId}
**Title:** ${activeItem.title}
**Trigger:** ${activeItem.trigger || "N/A"}
**Audience:** ${activeItem.audience || "N/A"}
**Rules:** ${activeItem.rules || "N/A"}
  `.trim();
}

// OUTPUT FINAL
return [
  {
    json: {
      activeType,
      activeId,
      activeItem,
      activeText: cleanText
    }
  }
];

